{
    "schemas": [
        "urn:ietf:params:scim:api:messages:2.0:BulkRequest"
    ],
    "Operations": [
        {
            "method": "PATCH",
            "path": "/Users/cce6c7c3-b69a-4258-b6b4-97e76c081e9d",
            "bulkId": "bulk-operation-1",
            "data": {
                "schemas":[
                    "urn:ietf:params:scim:api:messages:2.0:PatchOp"
                    ], 
                    "Operations": [
                    {
                        "op": "add",  //use add to add new value
                        "path": "urn:ietf:params:scim:schemas:extension:spend:2.0:User:biManager",
                         "value": {
                            "employeeNumber": "sandbox1approver2"
                        }
                    },
                    {
                        "op": "add",
                        "path": "urn:ietf:params:scim:schemas:extension:spend:2.0:Approver:report",
                        "value": [
                            {
                                "approver":{ "employeeNumber":"sandbox1approver2"},
                                "primary": true
                            }
                        ]
                    },
                    {
                        "op": "add", /* add travel manager */
                        "path": "urn:ietf:params:scim:schemas:extension:travel:2.0:User:manager",
                        "value":{ 
                                    "employeeNumber":"sandbox1approver2"
                                }


                    },
                    {  //use replace to replace existing value
                        "op":"replace",
                        "path": "urn:ietf:params:scim:schemas:extension:spend:2.0:User:customData[id eq \"custom4\"].value",
                        "value": "NewValue"
                    },
                    { //use remove to remove the value
                        "op": "remove",
                        "path": "urn:ietf:params:scim:schemas:extension:spend:2.0:user:customData[id eq \"orgUnit5\"]"
                    }
                ]
            }
        }
    ]
}

